import { MarkdownPowerPluginOptions } from "../shared/index.js";
import { LocaleConfig, LocaleData } from "vuepress";

//#region src/shared/encrypt.d.ts
/**
 * Encrypt Snippet Locale
 *
 * 加密片段本地化
 */
interface EncryptSnippetLocale extends LocaleData {
  /**
   * Hint message
   *
   * 提示信息
   * @default 'The content is encrypted, please unlock to view.'
   */
  hint?: string;
  /**
   * Password placeholder
   *
   * 密码占位符
   * @default 'Enter password'
   */
  placeholder?: string;
  /**
   * Incorrect password message
   *
   * 密码错误消息
   * @default 'Incorrect password'
   */
  incPwd?: string;
  /**
   * No content message
   *
   * 无内容消息
   * @default 'Unlocked, but content failed to load, please try again later.'
   */
  noContent?: string;
  /**
   * Security warning title
   *
   * 安全警告标题
   * @default '🚨 Security Warning:'
   */
  warningTitle?: string;
  /**
   * Security warning text
   *
   * 安全警告文本
   * @default 'Your connection is not encrypted with HTTPS, posing a risk of content leakage and preventing access to encrypted content.'
   */
  warningText?: string;
}
//#endregion
//#region src/client/options.d.ts
/**
 * Plugin options injected at build time.
 *
 * 构建时注入的插件选项。
 */
declare const pluginOptions: MarkdownPowerPluginOptions;
/**
 * Package installation status for video streaming libraries.
 *
 * 视频流媒体库的安装状态。
 */
declare const installed: {
  dashjs: boolean;
  hlsjs: boolean;
  mpegtsjs: boolean;
};
/**
 * Supported video types for ArtPlayer.
 *
 * ArtPlayer 支持的视频类型。
 */
declare const ART_PLAYER_SUPPORTED_VIDEO_TYPES: string[];
/**
 * Injection key for timeline component communication.
 *
 * 时间线组件通信的注入键。
 */
declare const INJECT_TIMELINE_KEY: symbol;
/**
 * Injection key for collapse component communication.
 *
 * 折叠面板组件通信的注入键。
 */
declare const INJECT_COLLAPSE_KEY: symbol;
/**
 * Encrypt snippet locale data.
 *
 * 加密片段本地化数据。
 */
declare const ENCRYPT_LOCALES: LocaleConfig<EncryptSnippetLocale>;
//#endregion
export { ART_PLAYER_SUPPORTED_VIDEO_TYPES, ENCRYPT_LOCALES, INJECT_COLLAPSE_KEY, INJECT_TIMELINE_KEY, installed, pluginOptions };